style.css: button:disabled { background-color: var(--color-surface25); cursor: not-allowed; } button:disabled:hover { border-color: var(--color-surface75); color: var(--color-surface75); } .wrapper { width: 100%; padding: 50px; } .gallery-container { width: 100%; display: flex; flex-wrap: wrap; justify-content: center; } .gallery-item { flex-basis: 25%; height: 400px; padding: 10px; } .small .gallery-item { flex-basis: 16.66667%; } .gallery-item .image-container { height: 90%; } .gallery-item .image-container img { height: 100%; width: 100%; object-fit: cover; }
script.js: console.clear(); gsap.registerPlugin(Flip); const btnSmall = document.getElementById("btnS"); const btnLarge = document.getElementById("btnL"); const galleryContainer = document.querySelector(".gallery-container"); const items = gsap.utils.toArray(".gallery-item"); btnSmall.addEventListener("click", () => { const state = Flip.getState(items); galleryContainer.classList.add("small"); btnSmall.setAttribute("disabled", true); btnLarge.removeAttribute("disabled"); Flip.from(state, { duration: 1, ease: "power1.inOut", absolute: true }); }); btnLarge.addEventListener("click", () => { const state = Flip.getState(items); galleryContainer.classList.remove("small"); btnSmall.removeAttribute("disabled"); btnLarge.setAttribute("disabled", true); Flip.from(state, { duration: 1, ease: "power1.inOut", absolute: true }); });
